    99→  ],
   100→}));
   101→
   102→type MenuItemDataType = {
   103→  name: string;
   104→  link?: string;
   105→  isSelected?: boolean;
   106→  icon: ReactElement;
   107→  isDivider?: boolean;
   108→};
   109→
   110→function LayoutInner({
   111→  children,
   112→  currentUser,
   113→  currentTeam,
   114→}: {
   115→  children: ReactNode;
   116→  currentUser: User;
   117→  currentTeam: Team;
   118→}) {
   119→  const { router, services } = useServicesHook();
   120→
   121→  const theme = useTheme();
   122→  const isSmallScreen = useMediaQuery(theme.breakpoints.down('md'));
   123→  const scrollTrigger = useScrollTrigger();
   124→
   125→  const [open, setOpen] = useState(!isSmallScreen);
   126→  const flipOpen = () => setOpen(!open);
   127→
   128→  const adminItem = {
   129→    name: translate(PAGE_INFO.ADMIN.name as keyof typeof translate),
   130→    icon: <AdminPanelSettingsOutlined />,
   131→    isSelected: router.pathname == PAGE_INFO.ADMIN.href(currentTeam.id),
   132→    link: PAGE_INFO.ADMIN.href(currentTeam.id),
   133→  };
   134→
   135→  const allResourceListItem = {
   136→    name: translate(
   137→      PAGE_INFO.MULTI_TEAMS_RESOURCES.name as keyof typeof translate,
   138→    ),
   139→    icon: <AdminPanelSettings />,
   140→    isSelected: router.pathname == PAGE_INFO.MULTI_TEAMS_RESOURCES.href(),
   141→    link: PAGE_INFO.MULTI_TEAMS_RESOURCES.href(),
   142→  };
   143→
   144→  const superAdminItems = [
   145→    {
   146→      name: translate(
   147→        PAGE_INFO.SUPER_ADMIN_TEAMS.name as keyof typeof translate,
   148→      ),
   149→      icon: <AdminPanelSettings />,
   150→      isSelected: router.pathname == PAGE_INFO.SUPER_ADMIN_TEAMS.href(),
   151→      link: PAGE_INFO.SUPER_ADMIN_TEAMS.href(),
   152→    },
   153→    {
   154→      name: translate(
   155→        PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS.name as keyof typeof translate,
   156→      ),
   157→      icon: <AdminPanelSettings />,
   158→      isSelected: router.pathname == PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS.href(),
   159→      link: PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS.href(),
   160→    },
   161→    {
   162→      name: translate(
   163→        PAGE_INFO.SUPER_ADMIN_AI_COACH.name as keyof typeof translate,
   164→      ),
   165→      icon: <AdminPanelSettings />,
   166→      isSelected: router.pathname == PAGE_INFO.SUPER_ADMIN_AI_COACH.href(),
   167→      link: PAGE_INFO.SUPER_ADMIN_AI_COACH.href(),
   168→    },
   169→  ];
   170→
   171→  const menuItems: MenuItemDataType[] = [
   172→    {
   173→      name: translate(PAGE_INFO.SESSIONS.name as keyof typeof translate),
   174→      icon: <FormatListBulleted />,
   175→      isSelected: router.pathname == PAGE_INFO.SESSIONS.href(currentTeam.id),
   176→      link: PAGE_INFO.SESSIONS.href(currentTeam.id),
   177→    },
   178→    {
   179→      name: translate(PAGE_INFO.PLAYERS.name as keyof typeof translate),
   180→      icon: <Groups3Outlined />,
   181→      isSelected: router.pathname == PAGE_INFO.PLAYERS.href(currentTeam.id),
   182→      link: PAGE_INFO.PLAYERS.href(currentTeam.id),
   183→    },
   184→    ...(User.isAccessible(
   185→      currentUser,
   186→      currentTeam.id,
   187→      'management',
   188→      'read',
   189→      true,
   190→    )
   191→      ? [adminItem]
   192→      : []),
   193→    {
   194→      name: '_divider_0',
   195→      icon: <></>,
   196→      isDivider: true,
   197→    },
   198→    {
   199→      name: translate(PAGE_INFO.NOTIFICATIONS.name as keyof typeof translate),
   200→      icon: <NotificationsOutlined />,
   201→      isSelected: router.pathname == PAGE_INFO.NOTIFICATIONS.href(),
   202→      link: PAGE_INFO.NOTIFICATIONS.href(),
   203→    },
   204→    ...(User.isAccessible(currentUser, 'all', 'management', 'read', false)
   205→      ? [
   206→        // This will be changed when new role-region is created.
   207→        {
   208→          name: '_divider_1',
   209→          icon: <></>,
   210→          isDivider: true,
   211→        },
   212→        allResourceListItem,
   213→      ]
   214→      : []),
   215→    ...(User.isAccessible(currentUser, 'all', 'management', 'read', false)
   216→      ? [
   217→        {
   218→          name: '_divider_2',
   219→          icon: <></>,
   220→          isDivider: true,
   221→        },
   222→        ...superAdminItems,
   223→      ]
   224→      : []),
   225→  ];
   226→
   227→  const closeDrawerOnSmallScreen = () => {
   228→    if (isSmallScreen) {
   229→      setOpen(false);
   230→    }
   231→  };
   232→
   233→  // プランステータスの判定
   234→  const getPlanStatus = (): { status: PlanStatus | null } => {
   235→    // Production環境では表示しない
   236→    if (EnvManager.isPrd || currentTeam.teamType === TeamType.MULTIPLE) {
   237→      return { status: null };
   238→    }
   239→
   240→    // 期限内のAppleサブスクリプションがある場合は表示しない
   241→    if (
   242→      currentTeam.teamPlan?.endDate &&
   243→      currentTeam.teamPlan.endDate > new Date() &&
   244→      currentTeam.teamPlan.subscriptionType === 'apple'
   245→    ) {
   246→      return { status: null };
   247→    }
   248→
   249→    // 支払い失敗の場合
   250→    if (
   251→      currentTeam.billingFailureReason !== null &&
   252→      currentTeam.billingFailureReason !== ''
   253→    ) {
   254→      return { status: 'billing_failure' };
   255→    }
   256→
   257→    // teamPlan が無料プランの場合
   258→    if (!currentTeam.teamPlan?.plan.isPaid) {
   259→      return { status: 'upgrade_prompt' };
   260→    }
   261→
   262→    // プランが利用不可の場合（期限切れや利用制限に達している場合）
   263→    if (!currentTeam.teamPlanAvailability.isAvailable) {
   264→      const reason = currentTeam.teamPlanAvailability.unavailableReason;
   265→      if (reason === 'team_plan_expired' || reason === 'no_team_plan_found') {
   266→        return { status: 'upgrade_prompt' };
   267→      }
   268→    }
   269→
   270→    // 既存のplanがisTopTierPlanの場合は表示しない
   271→    if (isTopTierPlan(currentTeam.teamPlan?.plan.id)) {
   272→      return { status: null };
   273→    }
   274→
   275→    // 利用制限に達している場合
   276→    if (currentTeam.ballRate >= 1) {
   277→      return { status: 'limit_reached' };
   278→    }
   279→
   280→    // 利用制限が近づいている場合
   281→    const isUsageLimitApproaching = currentTeam.ballRate >= 0.9;
   282→    if (isUsageLimitApproaching) {
   283→      return { status: 'pre_warning' };
   284→    }
   285→
   286→    // その他の場合は常にUpgrade promptを表示
   287→    return { status: 'upgrade_prompt' };
   288→  };
   289→
   290→  const planStatus = getPlanStatus();
   291→
   292→  const handleUpgrade = () => {
   293→    // 期限内のStripeサブスクリプションがある場合は請求ポータルを開く
   294→    if (currentTeam.teamPlan?.subscriptionType === 'stripe') {
   295→      handleBillingPortal(planStatus.status);
   296→      return;
   297→    }
   298→    // 期限内のTeamPlanがない場合はプラン選択ページに遷移
   299→    router.push('/account/plans');
   300→  };
   301→
   302→  const handleBillingPortal = async (status: PlanStatus | null) => {
   303→    try {
   304→      let type:
   305→        | 'subscription_update'
   306→        | 'subscription_cancel'
   307→        | 'payment_method_update'
   308→        | undefined;
   309→      if (status === 'billing_failure') {
   310→        type = 'payment_method_update';
   311→      } else if (
   312→        status === 'upgrade_prompt' ||
   313→        status === 'pre_warning' ||
   314→        status === 'limit_reached'
   315→      ) {
   316→        type = 'subscription_update';
   317→      }
   318→
   319→      const result = await services.default.payment.createBillingPortalSession({
   320→        teamId: currentTeam.id,
   321→        type,
   322→      });
   323→      if (result.error) {
   324→        throw result.error;
   325→      }
   326→      if (result.data?.url) {
   327→        window.open(result.data.url, '_blank', 'noopener,noreferrer');
   328→      }
   329→    } catch (error) {
   330→      enqueueSnackbar({
   331→        variant: 'error',
   332→        message: translate('payment_error_occurred'),
   333→      });
   334→    }
   335→  };
   336→
   337→  return (
   338→    <>
   339→      <Box sx={{ display: { xs: 'block', md: 'none' } }}>
   340→        <Slide appear={false} direction="down" in={!scrollTrigger}>
   341→          <AppBar variant="outlined" color="inherit" elevation={0}>
   342→            <Toolbar sx={{ display: 'flex', justifyContent: 'space-between' }}>
   343→              <Box sx={{ display: 'flex', flex: 1 }}>
   344→                <IconButton
   345→                  size="large"
   346→                  edge="start"
   347→                  color="inherit"
   348→                  aria-label="menu"
   349→                  sx={{ mr: 2 }}
   350→                  onClick={flipOpen}
   351→                >
   352→                  <MenuIcon />
   353→                </IconButton>
   354→              </Box>
   355→              <Box sx={{ display: 'flex', flex: 1, justifyContent: 'center' }}>
   356→                <Image
   357→                  src={AppConstants.LOGO_URL}
   358→                  alt=""
   359→                  priority={true}
   360→                  height="40"
   361→                  width="150"
   362→                />
   363→              </Box>
   364→              <Box sx={{ display: 'flex', flex: 1 }} />
   365→            </Toolbar>
   366→          </AppBar>
   367→        </Slide>
   368→        <Toolbar />
   369→      </Box>
   370→      <Box sx={{ display: 'flex' }}>
   371→        <Drawer
   372→          open={open}
   373→          onClose={flipOpen}
   374→          variant={isSmallScreen ? 'temporary' : 'permanent'}
   375→          slotProps={{
   376→            root: {
   377→              keepMounted: true, // Better open performance on mobile.
   378→            },
   379→          }}
   380→        >
   381→          <List sx={{ flex: 1 }}>
   382→            <ListItem disablePadding>
   383→              <ListItemButton
   384→                onClick={flipOpen}
   385→                sx={{
   386→                  justifyContent: 'space-between',
   387→                }}
   388→              >
   389→                <Image
   390→                  src={AppConstants.LOGO_URL}
   391→                  alt=""
   392→                  priority={true}
   393→                  height="40"
   394→                  width="150"
   395→                  style={{ display: open ? 'block' : 'none' }}
   396→                />
   397→                <ListItemIcon
   398→                  sx={{
   399→                    minWidth: 0,
   400→                    mr: open ? 1 : 'auto',
   401→                    justifyContent: 'center',
   402→                  }}
   403→                >
   404→                  {open ? (
   405→                    <KeyboardDoubleArrowLeft />
   406→                  ) : (
   407→                    <KeyboardDoubleArrowRight />
   408→                  )}
   409→                </ListItemIcon>
   410→              </ListItemButton>
   411→            </ListItem>
   412→            <Divider sx={{ mt: 2, mb: 6 }} />
   413→            <ListItem sx={{ opacity: open ? 1 : 0, mb: 2, py: 0 }}>
   414→              <Typography>{translate('navigation')}</Typography>
   415→            </ListItem>
   416→            {menuItems.map((x) => {
   417→              return (
   418→                <React.Fragment key={x.name}>
   419→                  {x.link ? (
   420→                    <ListItem disablePadding>
   421→                      <Link
   422→                        href={x.link}
   423→                        passHref
   424→                        style={{ width: '100%', textDecoration: 'none' }}
   425→                        onClick={closeDrawerOnSmallScreen}
   426→                      >
   427→                        <ListItemButton
   428→                          selected={!!x.isSelected}
   429→                          sx={{
   430→                            justifyContent: 'center',
   431→                          }}
   432→                        >
   433→                          <ListItemIcon
   434→                            sx={{
   435→                              minWidth: 0,
   436→                              mr: open ? 3 : 'auto',
   437→                              justifyContent: 'center',
   438→                            }}
   439→                          >
   440→                            {x.icon}
   441→                          </ListItemIcon>
   442→                          <ListItemText
   443→                            primary={x.name}
   444→                            sx={{
   445→                              opacity: open ? 1 : 0,
   446→                            }}
   447→                          />
   448→                        </ListItemButton>
   449→                      </Link>
   450→                    </ListItem>
   451→                  ) : x.isDivider ? (
   452→                    <Divider sx={{ my: 1 }} />
   453→                  ) : (
   454→                    <></>
   455→                  )}
   456→                </React.Fragment>
   457→              );
   458→            })}
   459→          </List>
   460→
   461→          {/* Plan Status Card */}
   462→          {planStatus.status !== null && (
   463→            <PlanStatusCard
   464→              status={planStatus.status}
   465→              open={open}
   466→              onUpgrade={handleUpgrade}
   467→            />
   468→          )}
   469→
   470→          {/* TODO: remove this */}
   471→          {!EnvManager.isPrd && (
   472→            <Box
   473→              className={'develop'}
   474→              sx={{ padding: 0.5, background: 'lightgray' }}
   475→            >
   476→              build: {EnvManager.config.APP_UPDATED_AT}
   477→              <br />
   478→              commit: {EnvManager.config.GIT_COMMIT_HASH}
   479→              <br />
   480→            </Box>
   481→          )}
   482→
   483→          <Box>
   484→            <Divider></Divider>
   485→            <Link
   486→              href={PAGE_INFO.ACCOUNT.href()}
   487→              passHref
   488→              style={{ width: '100%', textDecoration: 'none' }}
   489→              onClick={closeDrawerOnSmallScreen}
   490→            >
   491→              <ListItemButton
   492→                selected={
   493→                  router.pathname == PAGE_INFO.ACCOUNT.href() ||
   494→                  router.pathname == PAGE_INFO.ACCOUNT_EDIT.href()
   495→                }
   496→                sx={{
   497→                  justifyContent: 'center',
   498→                }}
   499→              >
   500→                <ListItemIcon
   501→                  sx={{
   502→                    minWidth: 0,
   503→                    mr: open ? 3 : 'auto',
   504→                    justifyContent: 'center',
   505→                  }}
   506→                >
   507→                  <ImageOrAvatar
   508→                    url={currentUser.profile?.presignedImageUrl}
   509→                    width={40}
   510→                    height={40}
   511→                  />
   512→                </ListItemIcon>
   513→                <ListItemText
   514→                  primary={currentUser?.profile?.username ?? '-'}
   515→                  sx={{
   516→                    opacity: open ? 1 : 0,
   517→                  }}
   518→                />
   519→              </ListItemButton>
   520→            </Link>
   521→          </Box>
   522→        </Drawer>
   523→        <Box
   524→          component="main"
   525→          sx={{
   526→            flexGrow: 1,
   527→            py: 2,
   528→            px: 2,
   529→            overflowX: 'auto',
   530→            minHeight: '100vh',
   531→            background: '#F9F9F9',
   532→          }}
   533→        >
   534→          {children}
   535→        </Box>
   536→      </Box>
   537→    </>
   538→  );
   539→}
   540→
   541→export default function ConsoleLayout({ children }: { children: ReactNode }) {
   542→  const { services, router } = useServicesHook();
   543→  const [_, setIsSubmitting] = useState<boolean>(false);
   544→  const currentUser = useSelector((state) => state.user.me);
   545→  const currentTeam = useSelector((state) => state.user.currentTeam);
   546→  const userError = useSelector((state) => state.user.error);
   547→  const loginStatus = useSelector((state) => state.user.loginStatus);
   548→
   549→  const logout = () => {
   550→    wrapForLoading(setIsSubmitting, async () => {
   551→      await services.default.auth.signOut();
   552→      location.href = PAGE_INFO.SIGN_IN.href();
   553→    });
   554→  };
   555→
   556→  useEffect(() => {
   557→    if (loginStatus === 'initial') {
   558→      return;
   559→    }
   560→
   561→    if (loginStatus != 'yes') {
   562→      logger.debug('SD: no user - redirect to signin');
   563→      const callbackUrl = createSafeCallbackUrl();
   564→      router.replace(`${PAGE_INFO.SIGN_IN.href()}?callbackUrl=${callbackUrl}`);
   565→    }
   566→  }, [loginStatus]);
   567→
   568→  if (loginStatus == 'error' && userError) {
   569→    return (
   570→      <>
   571→        <CriticalError error={userError} />
   572→      </>
   573→    );
   574→  }
   575→
   576→  return currentUser && currentTeam ? (
   577→    <LayoutInner currentUser={currentUser} currentTeam={currentTeam}>
   578→      {children}
   579→    </LayoutInner>
   580→  ) : currentUser ? (
   581→    <Box
   582→      sx={{
   583→        p: 2,
   584→      }}
   585→    >
   586→      <Typography>{translate('no_active_teams_found')}</Typography>
   587→      <Button color="error" sx={{ mt: 2 }} variant="contained" onClick={logout}>
   588→        {translate('sign_out')}
   589→      </Button>
   590→    </Box>
   591→  ) : (
   592→    <>
   593→      {
   594→        // nothing to do (waiting initialization)
   595→      }
   596→    </>
   597→  );
   598→}
