import { BaseModel, CastableTypes } from './base-model';
import { Plan } from './plan';

export class TeamPlan extends BaseModel {
  static _cast: Partial<Record<keyof TeamPlan, CastableTypes>> = {
    startDate: 'date',
    endDate: 'date',
    createdAt: 'date',
    updatedAt: 'date',
  };

  id!: string;
  teamId!: string;
  planId!: string;
  currentUsage!: number;
  currentAiCoachUsage!: number;
  startDate!: Date;
  endDate!: Date;
  isActive!: boolean;
  isPendingActivation!: boolean;
  createdAt!: Date;
  updatedAt!: Date;

  plan: Plan;
  appleSubscription: any | null = null;
  stripeSubscription: any | null = null;

  constructor(data?: any) {
    super();
    this.init(TeamPlan, data);
    const plan = Plan.newInstance(Plan, data?.plan);
    if (!plan) {
      throw new Error(`No plan: ${data}`);
    }
    this.plan = plan;
    this.appleSubscription = data?.appleSubscription ?? null;
    this.stripeSubscription = data?.stripeSubscription ?? null;
  }

  get subscriptionType(): 'apple' | 'stripe' | null {
    if (this.appleSubscription) {
      return 'apple';
    }
    if (this.stripeSubscription) {
      return 'stripe';
    }
    return null;
  }

  get isInAppleSubscription(): boolean {
    return (
      this.endDate &&
      this.endDate > new Date() &&
      this.subscriptionType === 'apple'
    );
  }
}

